function dfs(node, parent, adj, vals, curMax, count) {
    if (vals[node] >= curMax) {
        if (vals[node] > curMax) {
            count[0]++;
            curMax = vals[node];
        }
        for (const next of adj[node]) {
            if (next !== parent) {
                dfs(next, node, adj, vals, curMax, count);
            }
        }
    }
}

function numberOfGoodPaths(vals, edges) {
    const n = vals.length;
    const adj = Array(n).fill(null).map(() => []);
    for (const edge of edges) {
        adj[edge[0]].push(edge[1]);
        adj[edge[1]].push(edge[0]);
    }
    const count = [0];
    for (let i = 0; i < n; i++) {
        dfs(i, -1, adj, vals, -1, count);
    }
    return count[0];
}
