import java.util.ArrayList;
import java.util.List;

public class GoodPaths {
    public static void dfs(int node, int parent, List<List<Integer>> adj, int[] vals, int curMax, int[] count) {
        if (vals[node] >= curMax) {
            if (vals[node] > curMax) {
                count[0]++;
                curMax = vals[node];
            }
            for (int next : adj.get(node)) {
                if (next != parent) {
                    dfs(next, node, adj, vals, curMax, count);
                }
            }
        }
    }

    public static int numberOfGoodPaths(int[] vals, int[][] edges) {
        int n = vals.length;
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (int[] edge : edges) {
            adj.get(edge[0]).add(edge[1]);
            adj.get(edge[1]).add(edge[0]);
        }
        int[] count = {0};
        for (int i = 0; i < n; i++) {
            dfs(i, -1, adj, vals, -1, count);
        }
        return count[0];
    }
}
